INSERT INTO monsters (name, name_en, climate_terrain, frequency, organization, activity_cycle, diet, intelligence, treasure, alignment, ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage, special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value, default_zone, has_ranged_attack, source_book, description) VALUES
('Kobold', 'Kobold', 'Jedes/Unterirdisch', 'common', 'Stamm', 'Nacht', 'Allesfresser', 'Durchschnittlich', 'J,O', 'LE', 7, '6', '1/2', 0.5, 20, '1', '1d4', 'Fallen', NULL, 0, 'S', 'Unsicher (2-4)', 3, 7, 'melee', FALSE, 'MM', 'Kleine, reptilienartige Humanoide, die in unterirdischen Höhlen leben und für ihre tödlichen Fallen bekannt sind.'),
('Xvart', 'Xvart', 'Gemäßigt/Hügel', 'common', 'Stamm', 'Nacht', 'Allesfresser', 'Niedrig', 'K', 'CE', 7, '6', '1', 1.0, 20, '1', '1d4+1', NULL, NULL, 0, 'S', 'Durchschnittlich (8-10)', 9, 15, 'melee', FALSE, 'MM', 'Kleine blauhäutige Humanoide, die in großen Gruppen angreifen und Ratten als Verbündete nutzen.'),
('Goblin', 'Goblin', 'Jedes/Unterirdisch', 'common', 'Stamm', 'Nacht', 'Allesfresser', 'Niedrig', 'K (C)', 'LE', 6, '6', '1-1', 0.5, 20, '1', '1d6', NULL, 'Infrarot 60''', 0, 'S', 'Durchschnittlich (7-10)', 8, 15, 'melee', FALSE, 'MM', 'Kleine, hinterhältige Humanoide die in unterirdischen Komplexen leben und größere Kreaturen als Reittiere nutzen.'),
('Orc', 'Orc', 'Jedes/Unterirdisch', 'common', 'Stamm', 'Nacht', 'Durchschnittlich', 'Durchschnittlich', 'L (C,O,Q×10,S)', 'LE', 6, '9', '1', 1.0, 19, '1', '1d8', NULL, NULL, 0, 'M', 'Durchschnittlich (8-10)', 9, 15, 'melee', FALSE, 'MM', 'Aggressive, schweinegesichtige Humanoide die in Stammesverbänden leben und häufig als Söldner dienen.'),
('Hobgoblin', 'Hobgoblin', 'Jedes/Unterirdisch', 'uncommon', 'Stamm', 'Jeder', 'Allesfresser', 'Durchschnittlich', 'J,M (D,Q×10)', 'LE', 5, '9', '1+1', 1.5, 19, '1', '1d8', NULL, NULL, 0, 'M', 'Standhaft (11-12)', 11, 35, 'melee', FALSE, 'MM', 'Disziplinierte, militärisch organisierte Humanoide die größer und stärker als Orks sind.'),
('Bugbear', 'Bugbear', 'Jedes/Unterirdisch', 'uncommon', 'Stamm', 'Jeder', 'Fleischfresser', 'Niedrig-Durchschnittlich', 'J,K (B,L,M,N)', 'CE', 5, '9', '3+1', 3.5, 17, '1', '2d4 oder nach Waffe', 'Überraschung -3', NULL, 0, 'L', 'Standhaft (11-12)', 11, 120, 'melee', FALSE, 'MM', 'Große, pelzige Humanoide die für ihre Heimlichkeit und Brutalität bei Überfällen bekannt sind.'),
('Gnoll', 'Gnoll', 'Jedes/Unterirdisch', 'uncommon', 'Stamm', 'Nacht', 'Fleischfresser', 'Niedrig', 'L,M (D,Q×5,S)', 'CE', 5, '9', '2', 2.0, 19, '1', '2d4 oder nach Waffe +2', NULL, NULL, 0, 'L', 'Standhaft (11-12)', 11, 35, 'melee', FALSE, 'MM', 'Hyänenköpfige Humanoide die in Rudeln jagen und für ihre Grausamkeit bekannt sind.'),
('Norker', 'Norker', 'Unterirdisch', 'rare', 'Stamm', 'Nacht', 'Allesfresser', 'Niedrig', 'K (O)', 'CE', 3, '9', '1+2', 1.5, 19, '1', '1d6', 'Fangzähne 1d3', NULL, 0, 'S', 'Standhaft (11-12)', 11, 35, 'melee', FALSE, 'MM', 'Entfernte Verwandte der Goblins mit extrem harter, knochiger Haut die als natürliche Rüstung dient.'),
('Lizardman', 'Lizard Man', 'Tropisch-Warm/Sumpf', 'uncommon', 'Stamm', 'Jeder', 'Allesfresser', 'Niedrig', 'D', 'N', 5, '6, Sw 12', '2+1', 2.5, 19, '1', '1d6+1', NULL, NULL, 0, 'M', 'Standhaft (11-12)', 11, 65, 'melee', FALSE, 'MM', 'Reptilienartige Humanoide die in Sümpfen und Marschen leben und primitive Stammesgesellschaften bilden.'),
('Troglodyte', 'Troglodyte', 'Unterirdisch', 'uncommon', 'Clan', 'Jeder', 'Fleischfresser', 'Niedrig', 'D', 'CE', 5, '12', '2', 2.0, 19, '3', '1d4/1d4/1d4+1', 'Gestank (SV-Gift oder -1)', 'Chamäleon-Haut', 0, 'M', 'Standhaft (11)', 11, 65, 'melee', FALSE, 'MM', 'Unterirdische Reptilien-Humanoide deren übler Gestank Feinde schwächt und die sich in Fels tarnen können.'),
('Bullywug', 'Bullywug', 'Tropisch/Sumpf', 'uncommon', 'Stamm', 'Jeder', 'Fleischfresser', 'Niedrig-Durchschnittlich', 'J,K', 'CE', 6, '3, Sw 9', '1', 1.0, 19, '3', '1d2/1d2/1d4+1', NULL, 'Sprung', 0, 'S', 'Durchschnittlich (8-10)', 9, 35, 'melee', FALSE, 'MM', 'Froschartige Humanoide die in Sümpfen leben und dort ihr Revier aggressiv gegen Eindringlinge verteidigen.'),
('Sahuagin', 'Sahuagin', 'Tropisch-Warm/Salzwasser', 'uncommon', 'Königreich', 'Nacht', 'Fleischfresser', 'Hoch', 'N (I,O,P,Q×5,S,X)', 'LE', 5, '12, Sw 24', '2+2', 2.5, 19, '1', '1d6+1 oder nach Waffe', 'Klauen/Biss im Nahkampf', NULL, 0, 'M', 'Standhaft (11-12)', 11, 175, 'melee', FALSE, 'MM', 'Gefürchtete Meeres-Humanoide mit einem unstillbaren Hass auf Oberflächenbewohner, auch "Seeteufel" genannt.'),
('Kuo-Toa', 'Kuo-Toa', 'Unterirdisch/Wasser', 'rare', 'Theokratie', 'Jeder', 'Allesfresser', 'Hoch', 'Z', 'NE', 4, '9, Sw 18', '2', 2.0, 19, '1', '2d4 oder nach Waffe', 'Blitzschlag (Peitsche)', 'Schleim (Waffen haften)', 0, 'M', 'Durchschnittlich (8-10)', 9, 65, 'melee', FALSE, 'MM', 'Fischäugige Unterirdische Kreaturen die Blibdoolpoolp verehren und über einzigartige Wahrnehmungsfähigkeiten verfügen.'),
('Drow', 'Drow', 'Unterirdisch', 'very rare', 'Clan/Haus', 'Jeder', 'Allesfresser', 'Genial-Überragend', 'N (G,W)', 'CE', 4, '12', '2', 2.0, 19, '1', 'Nach Waffe', 'Magie (Dunkelheit, Feenfeuer)', 'Magieresistenz', 50, 'M', 'Elite (13-14)', 13, 650, 'ranged', TRUE, 'MM', 'Dunkelelfen aus den Tiefen der Erde mit angeborener Magie und einer grausamen, matriarchalischen Gesellschaft.'),
('Duergar', 'Duergar', 'Unterirdisch', 'rare', 'Clan', 'Jeder', 'Allesfresser', 'Durchschnittlich-Hoch', 'M (G,Q×20)', 'LE', 4, '6', '1+2', 1.5, 19, '1', 'Nach Waffe', 'Vergrößerung, Unsichtbarkeit', 'Magieresistenz', 0, 'S', 'Elite (13-14)', 13, 175, 'melee', FALSE, 'MM', 'Graue Zwerge der Underdark die über psionische Fähigkeiten wie Vergrößerung und Unsichtbarkeit verfügen.'),
('Derro', 'Derro', 'Unterirdisch', 'rare', 'Clan', 'Jeder', 'Allesfresser', 'Hoch', 'M (I,O)', 'CE', 5, '9', '3', 3.0, 17, '1', 'Nach Waffe', 'Gift, Wahnsinn-Magie', 'Magieresistenz 30%', 30, 'S', 'Standhaft (12)', 12, 175, 'melee', FALSE, 'MM', 'Wahnsinnige Zwergenverwandte aus dem Underdark die für ihre Grausamkeit und seltsame Magie gefürchtet werden.'),
('Githyanki', 'Githyanki', 'Astral/Jedes', 'very rare', 'Monarchie', 'Jeder', 'Allesfresser', 'Außergewöhnlich', 'R,S', 'CE', 5, '12', '3+3', 3.5, 17, '1', '2d4+2 (Silberschwerter)', 'Psionische Kräfte', 'Magieresistenz', 0, 'M', 'Elite (13-14)', 13, 270, 'melee', FALSE, 'MM', 'Astrale Krieger die einst Sklaven der Illithiden waren und nun mit ihren Silberschwertern das Multiversum durchstreifen.'),
('Githzerai', 'Githzerai', 'Limbo/Jedes', 'very rare', 'Monarchie', 'Jeder', 'Allesfresser', 'Außergewöhnlich', 'R,S', 'CN', 5, '12', '3+3', 3.5, 17, '1', '1d8+2', 'Psionische Kräfte', 'Magieresistenz', 0, 'M', 'Elite (13-14)', 13, 270, 'melee', FALSE, 'MM', 'Disziplinierte Bewohner von Limbo und Todfeinde der Githyanki, die psionische Meisterschaft anstreben.'),
('Ogre', 'Ogre', 'Jedes', 'common', 'Horde', 'Jeder', 'Fleischfresser', 'Niedrig', 'B (Q×10,S)', 'CE', 5, '9', '4+1', 4.5, 17, '1', '1d10+6', NULL, NULL, 0, 'L', 'Standhaft (11-12)', 11, 270, 'melee', FALSE, 'MM', 'Große, dumme Humanoide die alles fressen was sie fangen können und oft als Söldner für intelligentere Kreaturen arbeiten.'),
('Ogermagier', 'Ogre Mage', 'Jedes/Kalt', 'rare', 'Clan', 'Jeder', 'Fleischfresser', 'Durchschnittlich-Hoch', 'E,S', 'LE', 4, '9, Fl 15', '5+2', 5.5, 15, '1', '1d12', 'Magie (Kältestrahl, Dunkelheit, Gasgestalt, Unsichtbarkeit, Polymorph)', 'Regeneration 1 HP/Runde, Flug', 0, 'L', 'Standhaft (13)', 13, 975, 'ranged', TRUE, 'MM', 'Gehörnte, blau- oder grünhäutige Oger mit angeborener Magie und der Fähigkeit die Gestalt zu wandeln.'),
('Troll', 'Troll', 'Jedes/Kalt', 'uncommon', 'Einzelgänger', 'Nacht', 'Fleischfresser', 'Niedrig', 'D', 'CE', 4, '12', '6+6', 6.5, 13, '3', '1d4+4/1d4+4/1d8+4', 'Zerfetzen (bei doppeltem Klauenhit)', 'Regeneration 3 HP/Runde', 0, 'L', 'Elite (13-14)', 13, 1400, 'melee', FALSE, 'MM', 'Schlanke, grünhäutige Riesen mit übernatürlicher Regeneration — nur Feuer und Säure können sie dauerhaft töten.'),
('Minotaurus', 'Minotaur', 'Unterirdisch', 'uncommon', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Niedrig', 'C', 'CE', 6, '12', '6+3', 6.5, 13, '2', '1d4/2d4 oder nach Waffe +3', 'Hörnerstoß bei Sturmangriff 2d4', 'Nie verirrt (Labyrinth-Sinn)', 0, 'L', 'Standhaft (12)', 12, 975, 'melee', FALSE, 'MM', 'Stierköpfige Humanoide die in Labyrinthen leben und sich dort nie verirren können.'),
('Ettin', 'Ettin', 'Kalt/Hügel', 'rare', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Niedrig', 'B,C (O,Q×10,S)', 'CE', 3, '12', '10', 10.0, 11, '2', '2d8/3d6 (zwei Keulen)', 'Überraschung nur 1 auf 1d10', NULL, 0, 'H', 'Standhaft (13)', 13, 3000, 'melee', FALSE, 'MM', 'Zweiköpfige Riesen — jeder Kopf kontrolliert einen Arm, was sie zu gefährlichen Kämpfern macht.'),
('Hügelriese', 'Hill Giant', 'Jedes/Hügel', 'uncommon', 'Stamm', 'Jeder', 'Allesfresser', 'Niedrig-Durchschnittlich', 'D', 'CE', 3, '12', '12+2', 12.5, 9, '1', '2d6+7 oder Fels 2d8', 'Felsschleudern (60 m)', NULL, 0, 'H', 'Standhaft (12)', 12, 5000, 'melee', TRUE, 'MM', 'Die kleinsten und primitivsten der echten Riesen, bekannt für ihre Brutalität und Gier.'),
('Steinriese', 'Stone Giant', 'Gemäßigt-Subtropisch/Berge', 'uncommon', 'Stamm', 'Jeder', 'Allesfresser', 'Durchschnittlich', 'D', 'N', 0, '12', '14+3', 14.5, 7, '1', '2d10 oder Fels 3d10', 'Felsschleudern (90 m)', 'Felsen fangen', 0, 'H', 'Elite (13-14)', 13, 8000, 'melee', TRUE, 'MM', 'Grauhäutige Riesen die in Bergfestungen leben und mit tödlicher Präzision Felsen schleudern.'),
('Frostriese', 'Frost Giant', 'Arktisch-Kalt/Berge', 'rare', 'Stamm', 'Jeder', 'Allesfresser', 'Niedrig-Durchschnittlich', 'E', 'CE', 0, '12', '14+4', 14.5, 7, '1', '2d8+9 oder Fels 2d10', 'Felsschleudern (60 m)', 'Kälteimmunität', 0, 'H', 'Elite (13-14)', 13, 8000, 'melee', TRUE, 'MM', 'Blauhäutige Riesen aus den eisigen Norden, immun gegen Kälte und gefürchtete Krieger.'),
('Feuerriese', 'Fire Giant', 'Warm/Berge-Vulkane', 'rare', 'Stamm', 'Jeder', 'Allesfresser', 'Durchschnittlich-Hoch', 'E', 'LE', -1, '12', '15+5', 15.5, 5, '1', '2d10+10 oder Fels 2d10', 'Felsschleudern (60 m)', 'Feuerimmunität', 0, 'H', 'Elite (13-14)', 13, 10000, 'melee', TRUE, 'MM', 'Massige, feuerrote Riesen die in Vulkanen und Schmieden leben und hervorragende Schmiede sind.'),
('Wolkenriese', 'Cloud Giant', 'Jedes/Berge-Wolken', 'very rare', 'Clan', 'Jeder', 'Allesfresser', 'Außergewöhnlich', 'E,Q×10', 'N (50% gut, 50% böse)', -1, '12', '16+7', 16.5, 3, '1', '6d6 oder Fels 2d12', 'Felsschleudern (100 m)', 'Geruchssinn', 0, 'H', 'Fanatic (15)', 15, 12000, 'melee', TRUE, 'MM', 'Majestätische Riesen die über den Wolken in schwebenden Burgen residieren und über den Sturm gebieten.'),
('Sturmriese', 'Storm Giant', 'Jedes/Berge-Meer', 'very rare', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Genial', 'E,Q×20,R', 'CG', -6, '15, Sw 15', '19+7', 19.5, 3, '1', '7d6 oder Fels 3d10', 'Blitzschlag (8d8), Magie', 'Blitz/Kälteimmunität', 0, 'G', 'Fanatic (16)', 16, 16000, 'ranged', TRUE, 'MM', 'Die mächtigsten und edelsten aller Riesen, die Blitze schleudern und Stürme kontrollieren können.');
INSERT INTO monsters (name, name_en, climate_terrain, frequency, organization, activity_cycle, diet, intelligence, treasure, alignment, ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage, special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value, default_zone, has_ranged_attack, source_book, description) VALUES
('Skelett', 'Skeleton', 'Jedes', 'common', 'Gruppe', 'Nacht', 'Keins', 'Nicht intelligent', 'Keins', 'N', 7, '12', '1', 1.0, 19, '1', '1d6', NULL, 'Immun gegen Schlaf/Bezauberung, Halbschaden durch Stichwaffen', 0, 'M', 'Spezial', 12, 65, 'melee', FALSE, 'MM', 'Animierte Knochengerüste, die blind dem Willen ihres Erschaffers folgen.'),
('Zombie', 'Zombie', 'Jedes', 'common', 'Gruppe', 'Nacht', 'Keins', 'Nicht intelligent', 'Keins', 'N', 8, '6', '2', 2.0, 19, '1', '1d8', NULL, 'Immun gegen Schlaf/Bezauberung, verliert immer Initiative', 0, 'M', 'Spezial', 12, 65, 'melee', FALSE, 'MM', 'Willenlose Untote, die langsam aber unaufhaltsam ihre Opfer verfolgen.'),
('Juju-Zombie', 'Juju Zombie', 'Jedes', 'very rare', 'Einzelgänger', 'Nacht', 'Keins', 'Niedrig', 'Keins', 'NE', 6, '9', '3+12hp', 3.5, 17, '1', '3d4', 'Klettern', 'Immun gegen Feuer/Blitz/Magiemissile, +1 Waffen nötig', 0, 'M', 'Spezial', 14, 975, 'melee', FALSE, 'MM', 'Mächtige Untote die ihre Kampffähigkeiten aus dem Leben behalten und extrem schwer zu vernichten sind.'),
('Ghul', 'Ghoul', 'Jedes', 'common', 'Rudel', 'Nacht', 'Leichen', 'Niedrig', 'B,T', 'CE', 6, '9', '2', 2.0, 19, '3', '1d3/1d3/1d6', 'Paralyse (Berührung, SV-Lähmung)', 'Immun gegen Schlaf/Bezauberung', 0, 'M', 'Standhaft (12)', 12, 65, 'melee', FALSE, 'MM', 'Leichenressende Untote deren Berührung Lebende lähmt. Elfen sind immun gegen ihre Paralyse.'),
('Ghast', 'Ghast', 'Jedes', 'rare', 'Rudel', 'Nacht', 'Leichen', 'Sehr', 'B,Q,R,S,T', 'CE', 4, '15', '4', 4.0, 17, '3', '1d4/1d4/1d8', 'Paralyse (auch Elfen), Gestank', 'Immun gegen Schlaf/Bezauberung', 0, 'M', 'Standhaft (12)', 12, 650, 'melee', FALSE, 'MM', 'Mächtigere Verwandte der Ghule, deren Paralyse sogar Elfen betrifft und deren Gestank überwältigend ist.'),
('Schatten', 'Shadow', 'Jedes', 'uncommon', 'Schwarm', 'Nacht', 'Keins', 'Niedrig', 'F', 'CE', 7, '12', '3+3', 3.5, 17, '1', '1d4+1', 'Stärke-Entzug (1 Punkt pro Treffer)', '+1 Waffen nötig, Immun gegen Schlaf/Bezauberung', 0, 'M', 'Spezial', 14, 420, 'melee', FALSE, 'MM', 'Undeutliche dunkle Gestalten die an Wänden und Böden entlanggleiten und die Lebenskraft ihrer Opfer aussaugen.'),
('Wight', 'Wight', 'Jedes', 'uncommon', 'Rudel', 'Nacht', 'Keins', 'Durchschnittlich', 'B', 'LE', 5, '12', '4+3', 4.5, 15, '1', '1d4', 'Stufenentzug (1 Stufe)', 'Silber- oder Magiewaffen nötig', 0, 'M', 'Elite (14)', 14, 1400, 'melee', FALSE, 'MM', 'Hasserfüllte Untote die mit einer einzigen Berührung eine Stufe an Erfahrung rauben können.'),
('Geisterscheinung', 'Wraith', 'Jedes', 'uncommon', 'Rudel', 'Nacht', 'Keins', 'Sehr', 'E', 'LE', 4, '12, Fl 24', '5+3', 5.5, 15, '1', '1d6', 'Stufenentzug (1 Stufe)', 'Silber- oder Magiewaffen nötig, Immun gegen Schlaf/Bezauberung', 0, 'M', 'Elite (15)', 15, 2000, 'melee', FALSE, 'MM', 'Körperlose Manifestationen reinen Hasses die durch Wände gleiten und die Essenz der Lebenden verschlingen.'),
('Mumie', 'Mummy', 'Trocken/Wüste', 'rare', 'Einzelgänger', 'Nacht', 'Keins', 'Niedrig', 'D', 'LE', 3, '6', '6+3', 6.5, 13, '1', '1d12', 'Furcht (SV-Zauber), Mumienfäule', 'Nur Magiewaffen (halbiert), Immun gegen Schlaf/Bezauberung/Gift', 0, 'M', 'Elite (15)', 15, 3000, 'melee', FALSE, 'MM', 'Einbalsamierte Untote die jeden mit Mumienfäule infizieren können und nur durch Magiewaffen verwundbar sind.'),
('Gespenst', 'Spectre', 'Jedes', 'rare', 'Einzelgänger', 'Nacht', 'Keins', 'Hoch', 'Q,X', 'LE', 2, '15, Fl 30', '7+3', 7.5, 13, '1', '1d8', 'Stufenentzug (2 Stufen!)', '+1 Waffen nötig', 0, 'M', 'Champion (15-16)', 15, 4000, 'melee', FALSE, 'MM', 'Schreckliche körperlose Untote die mit jedem Treffer gleich zwei Erfahrungsstufen rauben.'),
('Vampir', 'Vampire', 'Jedes', 'rare', 'Einzelgänger', 'Nacht', 'Blut', 'Außergewöhnlich', 'F', 'CE', 1, '12, Fl 18', '8+3', 8.5, 11, '1', '5d4', 'Stufenentzug (2 Stufen), Bezauberung (Blick)', '+1 Waffen nötig, Regeneration 3 HP/Runde, Gasgestalt, Spinnenklettern', 0, 'M', 'Champion (16)', 16, 8000, 'melee', FALSE, 'MM', 'Die gefürchtetsten aller gewöhnlichen Untoten — mächtig, intelligent und nahezu unzerstörbar.'),
('Geist', 'Ghost', 'Jedes', 'very rare', 'Einzelgänger', 'Nacht', 'Keins', 'Hoch', 'E,S', 'LE', 0, 'Fl 9', '10', 10.0, 11, '1', 'Altern 10-40 Jahre', 'Magie-Glas, Besitz', 'Nur auf Ätherebene treffbar, Immun gegen Schlaf/Bezauberung', 0, 'M', 'Spezial', 14, 7000, 'melee', FALSE, 'MM', 'Ruhelose Seelen deren bloßer Anblick altern lässt und die Körper von Lebenden besitzen können.'),
('Lich', 'Lich', 'Jedes', 'very rare', 'Einzelgänger', 'Nacht', 'Keins', 'Überragend', 'A', 'NE', 0, '6', '11+', 11.0, 9, '1', '1d10', 'Paralyse-Berührung, Magie (18.+ Stufe)', '+1 Waffen nötig, Immun gegen Schlaf/Bezauberung/Kälte', 0, 'M', 'Fanatic (18)', 18, 12000, 'ranged', TRUE, 'MM', 'Untote Magier von unvorstellbarer Macht die ihre Seele in einem Phylakterium verwahren.'),
('Banshee', 'Banshee', 'Jedes', 'very rare', 'Einzelgänger', 'Nacht', 'Keins', 'Außergewöhnlich', 'D', 'CE', 0, 'Fl 15', '7', 7.0, 13, '1', '1d8', 'Todesschrei (SV-Tod oder sterben)', '+1 Waffen nötig, Magieresistenz 50%', 50, 'M', 'Fanatic (18)', 18, 4000, 'melee', FALSE, 'MM', 'Geisterhafte Elfengestalten deren markerschütternder Schrei sofortigen Tod bringen kann.'),
('Revenant', 'Revenant', 'Jedes', 'very rare', 'Einzelgänger', 'Nacht', 'Keins', 'Außergewöhnlich', 'Keins', 'N', 10, '9', '8', 8.0, 13, '1', '2d8', 'Paralyse (Blick, SV-Lähmung)', 'Regeneration, Immun gegen Schlaf/Bezauberung, +1 Waffen nötig', 0, 'M', 'Fanatic (20)', 20, 5000, 'melee', FALSE, 'MM', 'Rachsüchtige Untote die von ihren Gräbern auferstehen um ihren Mörder zu finden und zu vernichten.'),
('Skelettritter', 'Skeleton Warrior', 'Jedes', 'very rare', 'Einzelgänger', 'Jeder', 'Keins', 'Genial', 'Keins', 'NE', 2, '6', '9+12hp', 9.5, 11, '1', 'Nach Waffe', 'Kampffähigkeit eines Kämpfers', '+1 Waffen nötig, Immun gegen Schlaf/Bezauberung/Kälte, Zaubern', 90, 'M', 'Fanatic (20)', 20, 8000, 'melee', FALSE, 'MM', 'Mächtige untote Krieger die einst Lords waren und nun dazu verdammt sind für immer zu kämpfen.'),
('Kryptenwächter', 'Crypt Thing', 'Jedes', 'rare', 'Einzelgänger', 'Jeder', 'Keins', 'Sehr', 'Keins', 'N', 3, '12', '6', 6.0, 15, '1', '1d8', 'Teleportation von Eindringlingen', 'Immun gegen Schlaf/Bezauberung', 0, 'M', 'Spezial', 14, 975, 'melee', FALSE, 'MM', 'Skeletthafter Wächter der Toten der Grabräuber durch Teleportation verwirrt und vertreibt.'),
('Huecuva', 'Huecuva', 'Jedes', 'rare', 'Einzelgänger', 'Nacht', 'Keins', 'Niedrig', 'Keins', 'CE', 3, '9', '2', 2.0, 19, '1', '1d6', 'Krankheit (SV-Gift)', 'Immun gegen Schlaf/Bezauberung, +1 Waffen nötig', 0, 'M', 'Standhaft (12)', 12, 270, 'melee', FALSE, 'MM', 'Untote abtrünnige Priester die als Strafe für ihren Glaubensbruch verdammt wurden.'),
('Todesritter', 'Death Knight', 'Jedes', 'very rare', 'Einzelgänger', 'Jeder', 'Keins', 'Genial', 'Keins', 'CE', 0, '12', '9+11', 9.5, 11, '1', '2d8+6 (Zweihandschwert)', 'Feuerball 1/Tag (20d6), Machtwort Töten, Furcht-Aura', 'Magieresistenz 75%, +1 Waffen nötig', 75, 'M', 'Fanatic (20)', 20, 14000, 'melee', FALSE, 'MM', 'Ehemals edle Ritter die durch unheilige Macht als untote Schrecken auferstanden sind — fast so mächtig wie Lichs.'),
('Poltergeist', 'Poltergeist', 'Jedes', 'rare', 'Einzelgänger', 'Nacht', 'Keins', 'Niedrig', 'Keins', 'LE', 0, 'Fl 6', '1/2', 0.5, 20, '0', '-', 'Telekinese (Gegenstände schleudern 1d4)', 'Unsichtbar, +1 Waffen nötig', 0, 'S', 'Durchschnittlich (8-10)', 9, 120, 'ranged', TRUE, 'MM', 'Unsichtbare Geister die Gegenstände durch die Luft schleudern und Lebende terrorisieren.');
INSERT INTO monsters (name, name_en, climate_terrain, frequency, organization, activity_cycle, diet, intelligence, treasure, alignment, ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage, special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value, default_zone, has_ranged_attack, source_book, description) VALUES
('Weißer Drache (Jung)', 'White Dragon (Young)', 'Arktisch', 'rare', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Niedrig', 'Spezial', 'CE', 3, '12, Fl 40, Sw 12', '6', 6.0, 15, '3', '1d4/1d4/2d8', 'Frostatem (Kegel, 7d6+1)', NULL, 0, 'L', 'Champion (15-16)', 15, 3000, 'melee', TRUE, 'MM', 'Der kleinste und dümmste der chromatischen Drachen — lebt in eisigen Höhlen und friert Beute mit seinem Frostodem ein.'),
('Weißer Drache (Erwachsen)', 'White Dragon (Adult)', 'Arktisch', 'rare', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Niedrig', 'Spezial', 'CE', 0, '12, Fl 40, Sw 12', '10', 10.0, 11, '3', '1d6/1d6/3d6', 'Frostatem (Kegel, 12d6+4)', 'Kälteimmunität', 0, 'H', 'Fanatic (17)', 17, 8000, 'melee', TRUE, 'MM', 'Ein ausgewachsener Weißer Drache, mächtig genug eine ganze Siedlung in Eis zu hüllen.'),
('Schwarzer Drache (Erwachsen)', 'Black Dragon (Adult)', 'Tropisch/Sumpf', 'uncommon', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Durchschnittlich', 'Spezial', 'CE', -1, '12, Fl 30, Sw 12', '12', 12.0, 9, '3', '1d6/1d6/3d8', 'Säureatem (Linie, 12d4+4)', 'Säureimmunität', 0, 'H', 'Fanatic (17)', 17, 10000, 'melee', TRUE, 'MM', 'Hinterhältiger Sumpfdrache der Säure speit und mit dunkler List Schätze hortet.'),
('Grüner Drache (Erwachsen)', 'Green Dragon (Adult)', 'Subtropisch/Wald', 'uncommon', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Sehr', 'Spezial', 'CE', -2, '9, Fl 30, Sw 9', '13', 13.0, 7, '3', '1d8/1d8/2d10', 'Giftatem (Wolke, 14d6+5)', 'Giftimmunität', 0, 'H', 'Fanatic (17)', 17, 12000, 'melee', TRUE, 'MM', 'Gerissener Walddrache der seine Beute durch Manipulation und seinen tödlichen Giftadem vernichtet.'),
('Blauer Drache (Erwachsen)', 'Blue Dragon (Adult)', 'Trocken/Wüste', 'rare', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Sehr', 'Spezial', 'LE', -3, '9, Fl 30, Br 4', '15', 15.0, 5, '3', '1d8/1d8/3d8', 'Blitzatem (Linie, 16d8+8)', 'Blitzimmunität', 0, 'H', 'Fanatic (18)', 18, 14000, 'ranged', TRUE, 'MM', 'Eitelster der chromatischen Drachen, herrscht über Wüsten und schleudert vernichtende Blitze.'),
