('Kupferdrache (Erwachsen)', 'Copper Dragon (Adult)', 'Trocken/Berge', 'rare', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Hoch', 'Spezial', 'CG', -2, '9, Fl 30, Jp 3', '14', 14.0, 7, '3', '1d6/1d6/5d4', 'Säure-/Verlangsamungs-Atem, Zauber', 'Säureimmunität', 0, 'H', 'Fanatic (17)', 17, 12000, 'ranged', TRUE, 'MM', 'Witzig und verspielt — Kupferdrachen lieben Rätsel und Scherzfragen über alles.'),
