('Lebende Rüstung', 'Animated Armor', 'Jedes', 'rare', 'Einzelgänger', 'Jeder', 'Keins', 'Nicht intelligent', 'Keins', 'N', 3, '9', '4', 4.0, 17, '1', '1d8', NULL, 'Immun gegen Schlaf/Bezauberung/Gift', 0, 'M', 'Spezial', 12, 270, 'melee', FALSE, 'MM', 'Magisch animierte Rüstungen die lautlos Eindringlinge angreifen und schwer von normaler Ausrüstung zu unterscheiden sind.'),
