('Werwolf', 'Werewolf', 'Jedes', 'uncommon', 'Rudel', 'Nacht', 'Fleischfresser', 'Durchschnittlich', 'B', 'CE', 5, '15', '5+1', 5.5, 15, '1', '2d4', 'Lykanthropie (bei Biss)', 'Nur Silber- oder +1 Waffen', 0, 'M', 'Standhaft (12)', 12, 420, 'melee', FALSE, 'MM', 'Die bekanntesten Lykanthropen — bei Vollmond verwandeln sie sich in rasende Wolfsmenschen.'),
('Werrate', 'Wererat', 'Jedes/Städtisch', 'uncommon', 'Rudel', 'Nacht', 'Allesfresser', 'Sehr', 'C,D', 'LE', 6, '12', '3+1', 3.5, 17, '1', '1d8', 'Lykanthropie (bei Biss)', 'Nur Silber- oder +1 Waffen', 0, 'S', 'Standhaft (12)', 12, 270, 'melee', FALSE, 'MM', 'Hinterhältige Ratten-Lykanthropen die in den Abwasserkanälen von Städten lauern.'),
('Wereber', 'Wereboar', 'Jedes', 'rare', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Durchschnittlich', 'B,C', 'N', 4, '12', '5+2', 5.5, 15, '1', '2d6', 'Lykanthropie (bei Biss)', 'Nur Silber- oder +1 Waffen', 0, 'L', 'Standhaft (12)', 12, 420, 'melee', FALSE, 'MM', 'Zähe Eber-Lykanthropen die in ihrer Tierform wild und nahezu unaufhaltsam sind.'),
('Nixe', 'Nixie', 'Gemäßigt/Süßwasser', 'uncommon', 'Stamm', 'Tag', 'Allesfresser', 'Durchschnittlich', 'Keins', 'N', 7, '6, Sw 12', '1', 1.0, 20, '1', '1d4', 'Bezauberung (10 Kreaturen, SV-Zauber -2)', NULL, 0, 'S', 'Durchschnittlich (7)', 7, 65, 'melee', FALSE, 'MM', 'Kleine Wasserfeen die Eindringlinge bezaubern und als Diener unter Wasser halten.'),
('Pixie', 'Pixie', 'Gemäßigt/Wald', 'rare', 'Clan', 'Tag', 'Allesfresser', 'Außergewöhnlich', 'K,L,M,N', 'NG', 5, '6, Fl 12', '1', 1.0, 20, '1', '1d4+Spezial', 'Polymorph-Pfeile, Schlaf-Pfeile', 'Natürliche Unsichtbarkeit', 25, 'S', 'Durchschnittlich (7)', 7, 175, 'ranged', TRUE, 'MM', 'Winzige, unsichtbare Feen die mit magischen Pfeilen Chaos stiften und Streiche spielen.'),
('Dryade', 'Dryad', 'Gemäßigt/Wald', 'rare', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Hoch', 'D,Q×5', 'N', 9, '12', '2', 2.0, 19, '1', '1d2 (Dolch)', 'Bezauberung (SV-Zauber -3)', 'Dimensionstor zum Baum', 50, 'M', 'Unsicher (4)', 4, 975, 'melee', FALSE, 'MM', 'Schüchterne Baumnymphen die mit ihrem übernatürlichen Charme Sterbliche in ihren Wald locken.'),
('Satyr', 'Satyr', 'Gemäßigt/Wald', 'rare', 'Herde', 'Jeder', 'Allesfresser', 'Durchschnittlich-Hoch', 'D,I,J,K', 'N', 5, '18', '5', 5.0, 15, '1', '2d4+Spezial', 'Panflöte (Schlaf, Furcht, Bezauberung)', 'Magieresistenz 50%', 50, 'M', 'Standhaft (12)', 12, 650, 'melee', FALSE, 'MM', 'Ziegenbeinige Waldbewohner die für ihre Feiern, Musik und ihre magischen Panflöten bekannt sind.'),
('Treant', 'Treant', 'Gemäßigt/Wald', 'rare', 'Hain', 'Jeder', 'Wasser, Mineralien', 'Sehr', 'Q×10', 'CG', 0, '12', '12', 12.0, 9, '2', '4d6/4d6', 'Bäume beleben (2 pro Runde)', 'Nie von normalen Feuern bedroht', 0, 'H', 'Standhaft (16)', 16, 7000, 'melee', FALSE, 'MM', 'Uralte, baumgestaltige Waldwächter die andere Bäume zum Leben erwecken können.');
INSERT INTO monsters (name, name_en, climate_terrain, frequency, organization, activity_cycle, diet, intelligence, treasure, alignment, ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage, special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value, default_zone, has_ranged_attack, source_book, description) VALUES
('Schwarzer Pudding', 'Black Pudding', 'Unterirdisch', 'uncommon', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Nicht intelligent', 'Keins', 'N', 6, '6', '10', 10.0, 11, '1', '3d8', 'Löst Metall und organisches Material auf', 'Immun gegen Säure/Kälte, Waffen teilen die Kreatur', 0, 'H', 'Spezial', 12, 4000, 'melee', FALSE, 'MM', 'Riesige schwarze Schleimansammlungen die alles außer Stein auflösen und sich bei Schwertschlägen teilen.'),
('Grauer Schleim', 'Gray Ooze', 'Unterirdisch', 'uncommon', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Animalisch', 'Keins', 'N', 8, '1', '3+3', 3.5, 17, '1', '2d8', 'Löst Metall auf', 'Immun gegen Kälte/Feuer', 0, 'M', 'Spezial', 12, 270, 'melee', FALSE, 'MM', 'Metallauflösender Schlamm der sich als nasser Fels tarnt und Rüstungen und Waffen zersetzt.'),
('Ockergelee', 'Ochre Jelly', 'Unterirdisch', 'uncommon', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Nicht intelligent', 'Keins', 'N', 8, '3', '6', 6.0, 15, '1', '3d4', 'Löst organisches Material auf', 'Immun gegen Blitz, Waffen teilen die Kreatur', 0, 'L', 'Spezial', 12, 975, 'melee', FALSE, 'MM', 'Ockerfarbener Schleim der sich durch Ritzen quetscht und organisches Material auflöst.'),
('Grüner Schleim', 'Green Slime', 'Unterirdisch', 'common', 'Kolonie', 'Jeder', 'Allesfresser', 'Nicht intelligent', 'Keins', 'N', 9, '0', '2', 2.0, 19, '0', 'Spezial', 'Verwandelt Fleisch in Grünen Schleim (1d4 Runden)', 'Nur durch Kälte/Feuer/Heilung zerstörbar', 0, 'M', 'Spezial', 12, 65, 'melee', FALSE, 'MM', 'Ätzende grüne Masse an Decken und Wänden die alles was sie berührt in mehr Schleim verwandelt.'),
('Gelatinöser Würfel', 'Gelatinous Cube', 'Unterirdisch', 'uncommon', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Nicht intelligent', 'V', 'N', 8, '6', '4', 4.0, 17, '1', '2d4', 'Paralyse (SV-Lähmung), Verschlingen', 'Nahezu unsichtbar (Überraschung 1-3)', 0, 'L', 'Spezial', 12, 650, 'melee', FALSE, 'MM', 'Transparenter gallertartiger Würfel der Korridore reinigt und alles Organische in sich auflöst.'),
('Kreischer', 'Shrieker', 'Unterirdisch', 'common', 'Kolonie', 'Jeder', 'Keins', 'Nicht intelligent', 'Keins', 'N', 7, '1', '3', 3.0, 17, '0', '-', 'Schreien (alarmiert Monster im Umkreis von 40 m)', NULL, 0, 'M', 'Spezial', 12, 120, 'melee', FALSE, 'MM', 'Pilze die bei Annäherung ohrenbetäubend schreien und damit alle Monster der Umgebung herbeirufen.'),
('Violetter Pilz', 'Violet Fungus', 'Unterirdisch', 'uncommon', 'Kolonie', 'Jeder', 'Fleischfresser', 'Nicht intelligent', 'Keins', 'N', 7, '1', '3', 3.0, 17, '1-4', '1d4 (Fäulnis)', 'Berührungs-Fäulnis', NULL, 0, 'M', 'Spezial', 12, 175, 'melee', FALSE, 'MM', 'Lila leuchtende Pilze neben Kreischern die mit ihren Tentakeln Fleisch zum Verwesen bringen.'),
('Gelber Schimmel', 'Yellow Mold', 'Unterirdisch', 'common', 'Kolonie', 'Jeder', 'Keins', 'Nicht intelligent', 'Keins', 'N', 9, '0', '2', 2.0, 19, '0', 'Spezial', 'Sporenwolke (1d8 Schaden, SV-Gift oder Tod)', 'Nur durch Feuer zerstörbar', 0, 'M', 'Spezial', 12, 65, 'melee', FALSE, 'MM', 'Gefährlicher Schimmel der bei Berührung tödliche Sporen freisetzt — nur durch Feuer vernichtbar.'),
('Senfgelee', 'Mustard Jelly', 'Unterirdisch', 'rare', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Nicht intelligent', 'Keins', 'N', 4, '3', '6+2', 6.5, 13, '1', '5d4', 'Organisches Material auflösen, Verlangsamungs-Dampf', 'Immun gegen Blitz/normales Feuer', 0, 'L', 'Spezial', 12, 1400, 'melee', FALSE, 'MM', 'Senffarbenes Gelee das einen verlangsamenden Dampf absondert und nahezu unaufhaltsam ist.'),
('Kristallschleim', 'Crystal Ooze', 'Unterirdisch', 'rare', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Nicht intelligent', 'Keins', 'N', 8, '1', '4', 4.0, 17, '1', '4d4', 'Paralyse (SV-Lähmung)', 'Nahezu unsichtbar in Wasser', 0, 'M', 'Spezial', 12, 650, 'melee', FALSE, 'MM', 'Kristallklarer Schleim der in Pfützen und flachen Gewässern lauert und kaum zu erkennen ist.');
INSERT INTO monsters (name, name_en, climate_terrain, frequency, organization, activity_cycle, diet, intelligence, treasure, alignment, ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage, special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value, default_zone, has_ranged_attack, source_book, description) VALUES
('Verlagerungsbestie', 'Displacer Beast', 'Gemäßigt/Wald', 'rare', 'Rudel', 'Jeder', 'Fleischfresser', 'Halb-', 'D', 'LE', 4, '15', '6', 6.0, 15, '2', '2d4/2d4', NULL, 'Verlagerung (-2 auf feindliche Angriffe)', 0, 'L', 'Elite (13-14)', 13, 975, 'melee', FALSE, 'MM', 'Sechsbeinige pantherhafte Kreaturen die eine optische Verschiebung erzeugen — man sieht sie nie dort wo sie wirklich sind.'),
('Blinzelhund', 'Blink Dog', 'Gemäßigt/Ebene', 'rare', 'Rudel', 'Jeder', 'Allesfresser', 'Durchschnittlich', 'C', 'LG', 5, '12', '4', 4.0, 17, '1', '1d6', 'Teleportation im Kampf', 'Teleportation (Schwer zu treffen)', 0, 'M', 'Durchschnittlich (8-10)', 9, 270, 'melee', FALSE, 'MM', 'Intelligente Hunde die sich im Kampf teleportieren — natürliche Erzfeinde der Verlagerungsbestien.'),
('Phasenspinne', 'Phase Spider', 'Jedes', 'rare', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Niedrig', 'D', 'N', 7, '6, Wb 15', '5+5', 5.5, 15, '1', '1d6+Gift', 'Gift (SV-Gift -2 oder Tod), Phasenwechsel', 'Phasenwechsel (Ätherebene)', 0, 'L', 'Standhaft (12)', 12, 1400, 'melee', FALSE, 'MM', 'Riesenspinnen die zwischen Material- und Ätherebene wechseln und mit tödlichem Gift zuschlagen.'),
('Basilisk', 'Basilisk', 'Unterirdisch', 'uncommon', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Animalisch', 'Keins', 'N', 4, '6', '6+1', 6.5, 13, '1', '1d10', 'Versteinerungsblick (SV-Versteinerung)', NULL, 0, 'M', 'Standhaft (12)', 12, 1400, 'melee', FALSE, 'MM', 'Achtbeinige Reptilien deren Blick Lebewesen in Stein verwandelt — selbst ihr Spiegelbild ist gefährlich.'),
('Cockatrice', 'Cockatrice', 'Gemäßigt/Wald', 'uncommon', 'Schwarm', 'Tag', 'Allesfresser', 'Animalisch', 'D', 'N', 6, '6, Fl 18', '5', 5.0, 15, '1', '1d3+Versteinerung', 'Versteinerung (Berührung, SV-Versteinerung)', 'Flug', 0, 'S', 'Standhaft (11-12)', 11, 650, 'melee', FALSE, 'MM', 'Hahnähnliche Wesen mit einem Eidechsenschwanz deren bloße Berührung versteinert.'),
('Medusa', 'Medusa', 'Gemäßigt/Jedes', 'rare', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Sehr', 'P,Q,O', 'LE', 5, '9', '6', 6.0, 15, '1', '1d4+Gift', 'Versteinerungsblick (SV-Versteinerung), Schlangenhaar (Gift)', 'Blick-Attacke', 0, 'M', 'Standhaft (12)', 12, 3000, 'melee', FALSE, 'MM', 'Schlangenharige Frauen deren Blick zu Stein verwandelt — einer der berühmtesten Schrecken der Mythologie.'),
('Gorgon', 'Gorgon', 'Gemäßigt/Ebene', 'rare', 'Herde', 'Jeder', 'Pflanzenfresser', 'Animalisch', 'Keins', 'N', 2, '12', '8', 8.0, 13, '1', '2d6', 'Versteinerungs-Atem (SV-Versteinerung)', 'Panzerung', 0, 'L', 'Standhaft (12)', 12, 4000, 'melee', TRUE, 'MM', 'Metallische Stiere die einen versteinernden Atem ausstoßen — nicht zu verwechseln mit der mythischen Medusa.'),
('Chimäre', 'Chimera', 'Gemäßigt-Tropisch/Berge', 'rare', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Halb-', 'F', 'CE', 6, '9, Fl 18', '9', 9.0, 11, '6', '1d3/1d3/1d4/1d4/2d4/3d4', 'Feueratem (Ziegenkopf, 3d8)', 'Flug', 0, 'L', 'Durchschnittlich (8-10)', 9, 4000, 'melee', TRUE, 'MM', 'Dreiköpfige Bestie — Löwe, Ziege und Drache vereint — die Feuer speit und wahllos alles angreift.'),
('Mantikor', 'Manticore', 'Jedes', 'uncommon', 'Rudel', 'Jeder', 'Fleischfresser', 'Niedrig', 'E', 'LE', 4, '12, Fl 18', '6+3', 6.5, 13, '3', '1d3/1d3/1d8', 'Schwanzstacheln (6/Runde, je 1d6, 60 m)', 'Flug', 0, 'L', 'Standhaft (12)', 12, 1400, 'ranged', TRUE, 'MM', 'Löwenkörper mit Fledermausflügeln und einem Schwanz voller tödlicher Stacheln die wie Geschosse fliegen.'),
('Peryton', 'Peryton', 'Berge', 'uncommon', 'Schwarm', 'Jeder', 'Fleischfresser', 'Durchschnittlich', 'B', 'CE', 7, '12, Fl 21', '4', 4.0, 17, '3', '4d4 (Geweih)', 'Geweih-Sturmangriff, benötigt menschliche Herzen', 'Nur +1 Waffen schaden', 0, 'M', 'Standhaft (11-12)', 11, 650, 'melee', FALSE, 'MM', 'Hirsch-Adler-Hybriden die menschliche Herzen fressen müssen um sich fortzupflanzen.'),
('Eulenbär', 'Owlbear', 'Gemäßigt/Wald', 'rare', 'Rudel', 'Jeder', 'Fleischfresser', 'Niedrig', 'C', 'N', 5, '12', '5+2', 5.5, 15, '3', '1d6/1d6/2d6', 'Umarmung (2d8 bei doppeltem Klauenhit)', NULL, 0, 'L', 'Standhaft (12)', 12, 420, 'melee', FALSE, 'MM', 'Magisch gezüchtete Kreuzung aus Eule und Bär — extrem territorial und unbarmherzig aggressiv.'),
('Ankheg', 'Ankheg', 'Gemäßigt/Acker', 'rare', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Nicht intelligent', 'C', 'N', 2, '12, Br 6', '3-8', 5.0, 15, '1', '3d6+1d4 (Säure)', 'Säurespucken (4d4, einmal/6 Stunden)', NULL, 0, 'L', 'Durchschnittlich (7-9)', 8, 975, 'melee', TRUE, 'MM', 'Riesige grabende Insekten die aus dem Boden schießen und Beute mit Säure auflösen.'),
('Wandelnder Hügel', 'Shambling Mound', 'Feucht/Sumpf', 'rare', 'Einzelgänger', 'Jeder', 'Allesfresser', 'Niedrig', 'A', 'N', 0, '6', '9+9', 9.5, 11, '2', '2d8/2d8', 'Umschlingung (automatisch 2d8+2d8)', 'Immun gegen Feuer, Blitze heilen, Halbschaden von Waffen', 0, 'L', 'Fanatic (17)', 17, 6000, 'melee', FALSE, 'MM', 'Pflanzliche Ungeheuer die Opfer verschlingen und durch Blitze stärker statt schwächer werden.'),
('Dunkelmantel', 'Darkmantle', 'Unterirdisch', 'uncommon', 'Kolonie', 'Jeder', 'Fleischfresser', 'Niedrig', 'Keins', 'N', 6, '6, Fl 9', '1+1', 1.5, 19, '1', '1d4+1', 'Umhüllen (Erstickung), Dunkelheits-Aura (5 m)', NULL, 0, 'S', 'Durchschnittlich (8-10)', 9, 35, 'melee', FALSE, 'MM', 'Stalaktitenartige Kreaturen die eine Dunkelheitsaura erzeugen und Köpfe ihrer Opfer umhüllen.'),
('Deckenlauerer', 'Lurker Above', 'Unterirdisch', 'uncommon', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Niedrig', 'D', 'N', 6, '1, Fl 9', '10', 10.0, 11, '1', '1d6+Ersticken', 'Umhüllen und Ersticken (Automatisch)', 'Tarnung als Höhlendecke', 0, 'H', 'Durchschnittlich (10)', 10, 3000, 'melee', FALSE, 'MM', 'Riesige mantelartige Kreaturen die als Höhlendecke getarnt auf Beute fallen und sie ersticken.'),
('Fallensteller', 'Trapper', 'Unterirdisch', 'rare', 'Einzelgänger', 'Jeder', 'Fleischfresser', 'Hoch', 'Keins', 'N', 4, '3', '12', 12.0, 9, '4', '4d4', 'Umschließen (automatisch 4d4/Runde)', 'Tarnung als Boden', 0, 'H', 'Standhaft (14)', 14, 6000, 'melee', FALSE, 'MM', 'Flache Kreaturen die sich als Boden tarnen, zuklappen und ihre Opfer langsam verdauen.'),
('Intellektverschlinger', 'Intellect Devourer', 'Unterirdisch', 'rare', 'Rudel', 'Jeder', 'Gehirne', 'Außergewöhnlich', 'B', 'CE', 4, '15', '6+6', 6.5, 13, '4', '1d4×4', 'Psionische Attacke (INT auf 0 reduzieren, Körper übernehmen)', '+3 Waffen nötig, Magieresistenz', 0, 'S', 'Standhaft (14)', 14, 5000, 'melee', FALSE, 'MM', 'Gehirnförmige Monster auf Beinen die den Verstand ihrer Opfer verschlingen und deren Körper übernehmen.'),
('Irrlicht', 'Will-o''-Wisp', 'Sumpf/Unterirdisch', 'rare', 'Einzelgänger', 'Nacht', 'Lebenskraft', 'Außergewöhnlich', 'Z', 'CE', -8, 'Fl 18', '9', 9.0, 11, '1', '2d8', NULL, 'Immun gegen alle Magie außer Magic Missile/Maze, Blitz heilt', 0, 'S', 'Spezial', 16, 7000, 'melee', FALSE, 'MM', 'Tödliche Lichterscheinungen die Reisende in Sümpfe locken — fast unmöglich zu treffen oder zu töten.'),
('Unsichtbarer Pirscher', 'Invisible Stalker', 'Jedes', 'very rare', 'Einzelgänger', 'Jeder', 'Keins', 'Hoch', 'Keins', 'N', 3, '12, Fl 12', '8', 8.0, 13, '1', '4d4', 'Überraschung', 'Unsichtbarkeit (natürlich)', 0, 'L', 'Spezial', 12, 3000, 'melee', FALSE, 'MM', 'Luftelementare die als unermüdliche Jäger beschworen werden — sie geben nie auf.');
INSERT INTO monsters (name, name_en, climate_terrain, frequency, organization, activity_cycle, diet, intelligence, treasure, alignment, ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage, special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value, default_zone, has_ranged_attack, source_book, description) VALUES
('Luftelemental (12 TW)', 'Air Elemental (12 HD)', 'Luftebene', 'very rare', 'Einzelgänger', 'Jeder', 'Keins', 'Niedrig', 'Keins', 'N', 2, 'Fl 36', '12', 12.0, 9, '1', '2d10', 'Wirbelwind (Kreaturen unter 3 HD), +1d8 in der Luft', '+2 Waffen nötig', 0, 'H', 'Standhaft (13)', 13, 7000, 'melee', FALSE, 'MM', 'Mächtiger Luftelemental der als Wirbelwind Feinde durch die Luft schleudert.'),
('Erdelemental (12 TW)', 'Earth Elemental (12 HD)', 'Erdebene', 'very rare', 'Einzelgänger', 'Jeder', 'Keins', 'Niedrig', 'Keins', 'N', 2, '6', '12', 12.0, 9, '1', '4d8', '+1d8 gegen Bodenkontakt', '+2 Waffen nötig, kann nicht fliegen', 0, 'H', 'Standhaft (13)', 13, 7000, 'melee', FALSE, 'MM', 'Massiger Erdelemental der Mauern und Befestigungen mit Leichtigkeit durchbricht.'),
('Feuerelemental (12 TW)', 'Fire Elemental (12 HD)', 'Feuerebene', 'very rare', 'Einzelgänger', 'Jeder', 'Keins', 'Niedrig', 'Keins', 'N', 2, '12', '12', 12.0, 9, '1', '3d8', 'Entzündet Brennbares, +1d8 gegen kältebasierte Kreaturen', '+2 Waffen nötig, Feuerimmunität, Wasser schwächt', 0, 'H', 'Standhaft (13)', 13, 7000, 'melee', FALSE, 'MM', 'Lodernder Feuerelemental der alles Brennbare in seiner Nähe entzündet.'),
('Wasserelemental (12 TW)', 'Water Elemental (12 HD)', 'Wasserebene', 'very rare', 'Einzelgänger', 'Jeder', 'Keins', 'Niedrig', 'Keins', 'N', 2, '6, Sw 18', '12', 12.0, 9, '1', '5d6', 'Boote kentern, +1d8 im Wasser', '+2 Waffen nötig, muss in der Nähe von Wasser bleiben', 0, 'H', 'Standhaft (13)', 13, 7000, 'melee', FALSE, 'MM', 'Gewaltiger Wasserelemental der Schiffe kentern lässt und Feinde in Wassermassen ertränkt.'),
('Mephit (Feuer)', 'Mephit (Fire)', 'Feuerebene', 'common', 'Schwarm', 'Jeder', 'Keins', 'Durchschnittlich', 'Keins', 'NE', 5, '12, Fl 24', '3+1', 3.5, 17, '2', '1d3/1d3', 'Feuerstrahl (1d8+1, 5 m), Magisches Feuer', 'Feuerimmunität, Regeneration 1 HP/Runde in Feuer', 0, 'M', 'Durchschnittlich (7-8)', 7, 270, 'ranged', TRUE, 'MM', 'Kleine, bösartige Feuergeister die Flammen speien und sich an der Qual anderer erfreuen.'),
('Mephit (Eis)', 'Mephit (Ice)', 'Wasserebene', 'common', 'Schwarm', 'Jeder', 'Keins', 'Durchschnittlich', 'Keins', 'NE', 5, '6, Fl 12', '3+1', 3.5, 17, '2', '1d3/1d3', 'Frosthauch (1d4, 1,5 m), Eiswolke', 'Kälteimmunität, Regeneration 1 HP/Runde in Kälte', 0, 'M', 'Durchschnittlich (7-8)', 7, 270, 'ranged', TRUE, 'MM', 'Eisige kleine Elementarwesen die Frosthauch verbreiten und alles einfrieren wollen.'),
('Galeb Duhr', 'Galeb Duhr', 'Berge', 'very rare', 'Einzelgänger', 'Tag', 'Mineralien', 'Durchschnittlich-Hoch', 'Keins', 'N', -2, '6', '10', 10.0, 11, '2', '2d8/2d8', 'Felsen beleben (1d2 pro Runde), Stampfen (SV oder fallen)', 'Magieresistenz 20%, Immun gegen Feuer/Blitz', 20, 'L', 'Fanatic (16)', 16, 6000, 'melee', FALSE, 'MM', 'Uralte Steinwesen die Felsbrocken zum Leben erwecken und ihre Bergheimaten fanatisch verteidigen.'),
('Salamander', 'Salamander', 'Feuerebene', 'rare', 'Clan', 'Jeder', 'Fleischfresser', 'Hoch', 'F', 'CE', 5, '9', '7+7', 7.5, 13, '2', '2d6/1d6+Hitze', 'Hitze-Aura (1d6 im Umkreis), Umschlingung', 'Immun gegen Feuer, +1 Waffen nötig', 0, 'M', 'Standhaft (13)', 13, 3000, 'melee', FALSE, 'MM', 'Feurige Schlangenwesen mit menschlichem Oberkörper, deren bloße Nähe verbrennend heiß ist.');
