-- ============================================================================
-- UPDATE typical_spells for spellcasting undead (not in their INSERT column list)
-- ============================================================================

UPDATE monsters SET typical_spells = '["fireball","power word stun","finger of death","globe of invulnerability","time stop","meteor swarm"]'::jsonb WHERE name_en = 'Lich';
UPDATE monsters SET typical_spells = '["wall of fire","power word kill","symbol of fear"]'::jsonb WHERE name_en = 'Death Knight';

-- ============================================================================
-- Verify count
-- ============================================================================

DO $$
DECLARE
  cnt INTEGER;
BEGIN
  SELECT COUNT(*) INTO cnt FROM monsters WHERE source_book = 'MM';
  RAISE NOTICE 'Total MM monsters seeded: %', cnt;
END $$;
